CREATE TABLE IF NOT EXISTS Genre ( Id INTEGER PRIMARY KEY AUTOINCREMENT, Name TEXT NOT NULL UNIQUE );
CREATE TABLE IF NOT EXISTS Author ( Id INTEGER PRIMARY KEY AUTOINCREMENT, FirstName TEXT NOT NULL, LastName TEXT NOT NULL );
CREATE TABLE IF NOT EXISTS Books ( Id INTEGER PRIMARY KEY AUTOINCREMENT, Title TEXT NOT NULL, Author Id INTEGER NOT NULL REFERENCES Author(Id), GenreId INTEGER NOT NULL REFERENCES Genre(Id), Year INTEGER, Pages INTEGER, Status TEXT NOT NULL DEFAULT 'NotRead', Notes TEXT);